from pydantic import BaseModel
import json


class User(BaseModel):
    id: int
    email: str
    active: bool = True


class Session(BaseModel):
    user: User
    token: str


def serialize(model):
    # BUG: pydantic v2 removed .dict() in favor of .model_dump()
    data = model.dict()
    return json.dumps(data)


def main():
    user = User(id=1, email='u@example.com')
    payload = serialize(user)
    print(payload)


if __name__ == '__main__':
    main()
